<template><SolutionDesignNodeLayout :workflow="workflow" :node="currentNode" :loading="context.solutionDesignLoading" :error-message="context.solutionDesignErrorMessage"><SolutionUploadSlots v-if="canViewFormContent" :slots="slots" :is-pending="isPending" @upload="handleUpload" @download="downloadUpload"/><section v-if="canViewFormContent" class="analysis-section"><h4>项目方案分析表</h4><el-descriptions :column="3" border><el-descriptions-item label="项目编号">{{project?.projectCode||project?.project_code||'-'}}</el-descriptions-item><el-descriptions-item label="项目名称">{{project?.projectName||project?.project_name||'-'}}</el-descriptions-item><el-descriptions-item label="客户名称">{{project?.customerName||project?.customer_name||'-'}}</el-descriptions-item></el-descriptions><SolutionFormFields :fields="analysisFields" :model="analysisFormData" :disabled="!analysisFormDto?.permissions?.canEditForm" @update="updateAnalysisFormField"/><h4>图片</h4><div class="image-grid"><article v-for="field in analysisImageFields" :key="field.key" class="image-card"><strong>{{field.label}}</strong><el-upload v-if="analysisFormDto?.permissions?.canEditForm" :show-file-list="false" accept="image/png,image/jpeg" :disabled="imagesFor(field).length>=field.maxImages" :http-request="options=>uploadAnalysisImage({field,file:options.file})"><el-button :disabled="imagesFor(field).length>=field.maxImages">选择图片（{{imagesFor(field).length}}/{{field.maxImages}}）</el-button></el-upload><div v-for="image in imagesFor(field)" :key="image.id" class="image-row"><span>{{image.originalFileName}}</span><div><el-button v-if="image.permissions?.canDownload!==false" link @click="downloadAnalysisImage({image})">下载</el-button><el-button v-if="image.permissions?.canDelete??analysisFormDto?.permissions?.canEditForm" type="danger" link @click="confirmDelete(image)">删除</el-button></div></div></article></div><SolutionGeneratedFile :generated-file="analysisFormDto?.form?.generatedFile" :pending="isPending('analysis:download')" @download="downloadAnalysisGeneratedFile"/><div class="action-row"><el-button :disabled="!analysisFormDto?.permissions?.canEditForm" :loading="isPending('analysis:save')" @click="saveAnalysisForm">保存草稿</el-button><el-button type="primary" :disabled="!analysisFormDto?.permissions?.canSubmitForm" :loading="isPending('analysis:submit')" @click="submitAnalysisForm">提交表单</el-button></div></section><SolutionGeneratedFile v-if="!canViewFormContent" :generated-file="analysisFormDto?.form?.generatedFile" :pending="isPending('analysis:download')" @download="downloadAnalysisGeneratedFile"/><SolutionNodeActions v-if="currentNode" :node="currentNode" :is-pending="isPending" :submit-disabled="generatedBlocksSubmit" :return-reason="returnReasons[nodeKey]||''" @update:return-reason="returnReasons[nodeKey]=$event" @submit="submitNode(nodeKey)" @approve="approveNode(nodeKey)" @return="returnNode(nodeKey)"/></SolutionDesignNodeLayout></template>
<script setup>import{computed,watch,onBeforeUnmount}from'vue';import{ElMessageBox}from'element-plus';import SolutionDesignNodeLayout from'../../../components/project-workspace/solution-design/SolutionDesignNodeLayout.vue';import SolutionUploadSlots from'../../../components/project-workspace/solution-design/SolutionUploadSlots.vue';import SolutionNodeActions from'../../../components/project-workspace/solution-design/SolutionNodeActions.vue';import SolutionFormFields from'../../../components/project-workspace/solution-design/SolutionFormFields.vue';import SolutionGeneratedFile from'../../../components/project-workspace/solution-design/SolutionGeneratedFile.vue';import{analysisFields,analysisImageFields}from'../../../components/project-workspace/solution-design/solutionDesignFields.js';import{solutionDesignNodePageProps,useSolutionDesignNodePage}from'../../../composables/project-stage/solution-design/useSolutionDesignNodePage.js';import{useSolutionAnalysisForm}from'../../../composables/project-stage/solution-design/useSolutionAnalysisForm.js';const emit=defineEmits(['business-state-changed']);const props=defineProps(solutionDesignNodePageProps);const base=useSolutionDesignNodePage(props,emit);const{context,workflow,nodeKey,currentNode,slots,canViewFormContent,localMessage,localError,returnReasons,isPending,runAction,handleUpload,downloadUpload,submitNode,approveNode,returnNode}=base;const analysis=useSolutionAnalysisForm({projectId:computed(()=>props.projectId),authToken:computed(()=>props.authToken),runAction,localMessage,localError});const{analysisFormDto,analysisFormData,syncFromWorkflow,loadAnalysisForm,invalidateRequests,updateAnalysisFormField,saveAnalysisForm,submitAnalysisForm,downloadAnalysisGeneratedFile,uploadAnalysisImage,downloadAnalysisImage,deleteAnalysisImage}=analysis;const images=computed(()=>analysisFormDto.value?.images||analysisFormDto.value?.form?.images||[]);const generatedBlocksSubmit=computed(()=>{const file=analysisFormDto.value?.form?.generatedFile;return Boolean(file)&&(file.status!=='generated'||file.canDownload!==true)});watch(workflow,value=>{syncFromWorkflow(value,true);void loadAnalysisForm()},{immediate:true});onBeforeUnmount(invalidateRequests);function imagesFor(field){return images.value.filter(item=>item.fieldKey===field.key)}async function confirmDelete(image){try{await ElMessageBox.confirm(`确认删除“${image.originalFileName||'该图片'}”吗？`,'删除确认',{type:'warning',confirmButtonText:'确认删除',cancelButtonText:'取消'});await deleteAnalysisImage({image})}catch{/*取消不请求*/}}</script>
